import React, { useEffect, useState } from 'react';
import { useLocation } from 'react-router-dom';
import jwt_decode from 'jwt-decode';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authorizationEndpoint = 'https://YOUR_AUTH_PROVIDER/authorize';
const tokenEndpoint = 'https://YOUR_AUTH_PROVIDER/token';
const scope = 'openid profile email';

const App = () => {
  const [user, setUser] = useState(null);
  const location = useLocation();

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const code = params.get('code');
    const state = params.get('state');

    if (code) {
      exchangeCodeForToken(code, state);
    }
  }, [location]);

  const login = () => {
    const state = Math.random().toString(36).substring(2);
    const authUrl = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${redirectUri}&scope=${scope}&state=${state}`;
    window.location.href = authUrl;
  };

  const exchangeCodeForToken = async (code, state) => {
    const response = await fetch(tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: redirectUri,
        client_id: clientId,
      }),
    });

    const data = await response.json();
    if (data.id_token) {
      const decoded = jwt_decode(data.id_token);
      setUser(decoded);
    }
  };

  return (
    <div>
      <h1>React OpenID Connect Authentication</h1>
      {user ? (
        <div>
          <h2>Welcome, {user.name}</h2>
          <pre>{JSON.stringify(user, null, 2)}</pre>
        </div>
      ) : (
        <button onClick={login}>Login</button>
      )}
    </div>
  );
};

export default App;